Hello,
Though I have updated ExcelJs in latest version but I still get the same problem about appending rows to existing table. 
My code is like
`const Excel = require('exceljs');
  const workbook = new Excel.Workbook();
  await workbook.xlsx.readFile(filepath + '/template_file.xlsx');
  const mysheet = workbook.getWorksheet('MyWorksheet');
        mysheet.unprotect();
        const mytable = mysheet.getTable('MyTable');
        for (var i: number = 0; i< myArray.length; i++) {
              mytable.addRow([
                myArray[i].field1,
                myArray[i].field2
            ]);
        }
       mytable.commit();
`

When I test with console.log(mytable) and I got 
`Table {
  worksheet: undefined,
  table: {
    name: 'MyTable',
    displayName: 'MyTable',
    tableRef: 'A1:N2',
    totalsRow: false,
    headerRow: false,
    columns: [
      [Object], [Object],
      [Object], [Object],
      [Object], [Object],
      [Object], [Object],
      [Object], [Object],
      [Object], [Object],
      [Object], [Object]
    ],
    autoFilterRef: 'A1:N2',
    style: {
      theme: 'TableStyleMedium2',
      showFirstColumn: false,
      showLastColumn: false,
      showRowStripes: true,
      showColumnStripes: false
    }
  }
}`

Thanks in advance for your help

This issue can be replicated simply by adding rows to an existing worksheet. Here are the steps to reproduce.

```ts
// setup writer
const workbookWriter = new WorkbookWriter({ filename: 'tmp/test.xslx' });
const worksheetName = 'Cool new sheet';

// create new sheet and add rows
const originalSheet = workbookWriter.addWorksheet(worksheetName);
await originalSheet.addRow(['Hello', 'World').commit();
await originalSheet.commit();

// retrieve the sheet a second time and add rows
const retreivedSheet = workbook.getWorksheet(worksheetName);
retreivedSheet.addRow(['One','Two']); // <-- throws here, even before committing row
```

The exception:
```
TypeError: Cannot read property 'length' of null
  at WorksheetWriter.get _nextRow [as _nextRow] (node_modules/exceljs/lib/stream/xlsx/worksheet-writer.js:308:39) 
  at WorksheetWriter.addRow (node_modules/exceljs/lib/stream/xlsx/worksheet-writer.js:374:36)
```

@jakawell I get the same error at exceljs@4.2.0 & node.js 10.23.
@Alanscut @bvisonl  @molant  I was able to avoid this issue with the patch below. 
  Please check someone else and make a pull request. 

--Before  ./Node_modules\exceljs\lib\stream\xlsx\worksheet-writer.js :  line number 228;
```

commit() {
    if (this.committed) {
      return;
    }
    // commit all rows
    this._rows.forEach(cRow => {
      if (cRow) {
        // write the row to the stream
        this._writeRow(cRow);
      }
    });

    // we _cannot_ accept new rows from now on
 -    this._rows = null;
```
--After  ./Node_modules\exceljs\lib\stream\xlsx\worksheet-writer.js :  line number 228;
```
 +    this._rows = [];
```
Only 1 line changed！

This patch works for me:
From 5835689cd79515dc0ca0678e35ab44483903889e Mon Sep 17 00:00:00 2001
From: Erich Ino <Erich2.Ino@extern.esg.de>
Date: Tue, 16 Mar 2021 10:12:53 +0100
Subject: [PATCH] - make table workable

---
 lib/doc/worksheet.js                | 42 +++++++++++++++++++++++++++--
 lib/xlsx/xform/table/table-xform.js |  1 +
 2 files changed, 41 insertions(+), 2 deletions(-)

diff --git a/lib/doc/worksheet.js b/lib/doc/worksheet.js
index f4b6088..ffc3be3 100644
--- a/lib/doc/worksheet.js
+++ b/lib/doc/worksheet.js
@@ -861,6 +861,7 @@ class Worksheet {
   }
 
   set model(value) {
+ 	const that = this; 
     this.name = value.name;
     this._columns = Column.fromModel(this, value.cols);
     this._parseRows(value);
@@ -875,8 +876,45 @@ class Worksheet {
     this._media = value.media.map(medium => new Image(this, medium));
     this.sheetProtection = value.sheetProtection;
     this.tables = value.tables.reduce((tables, table) => {
-      const t = new Table();
-      t.model = table;
+      /**
+       * Once we have the table information and the sheet we can add the rows related to it.
+       * We parse the start and end via the reference and then we iterate over all the
+       * cells the sheet has to see if they are inside the table to add their values to its rows.
+       */
+      const [
+        ,
+        startColumnStr,
+        startRowStr,
+        endColumnStr,
+        endRowStr
+      ] = /(\D+)(\d+):(\D+)(\d+)/i.exec(table.tableRef);
+      var startColumn = 0;
+      for (let i = 0; i < startColumnStr.length; i++)
+        startColumn =
+          startColumn * 26 + startColumnStr[i].toUpperCase().charCodeAt(0) - 64;
+      var endColumn = 0;
+      for (let i = 0; i < endColumnStr.length; i++)
+        endColumn =
+          endColumn * 26 + endColumnStr[i].toUpperCase().charCodeAt(0) - 64;
+      const startRow = parseInt(startRowStr, 10);
+      const endRow = parseInt(endRowStr, 10);
+      const offset = table.headerRow ? 1 : 0;
+      const rows = [];
+
+      for (let i = startRow + offset; i <= endRow; i++) {
+        const rowValues = [];
+        that.getRow(i).eachCell((cell, colNumber) => {
+          if (colNumber >= startColumn && colNumber <= endColumn) {
+            rowValues.push(cell.value);
+          }
+        });
+        rows.push(rowValues);
+      }
+
+      table.rows = rows;
+
+      // Need to pass `that` so the table has a sheet associated
+      const t = new Table(that, table);
       tables[table.name] = t;
       return tables;
     }, {});
diff --git a/lib/xlsx/xform/table/table-xform.js b/lib/xlsx/xform/table/table-xform.js
index 002fbda..fdf7177 100644
--- a/lib/xlsx/xform/table/table-xform.js
+++ b/lib/xlsx/xform/table/table-xform.js
@@ -64,6 +64,7 @@ class TableXform extends BaseXform {
         this.model = {
           name: attributes.name,
           displayName: attributes.displayName || attributes.name,
+		  ref: attributes.ref,
           tableRef: attributes.ref,
           totalsRow: attributes.totalsRowCount === '1',
           headerRow: attributes.headerRowCount === '1',
